import scala.collection.mutable

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
    val n = online.length
    if (n == 0) return -1
    val maxEdge = if (edges.isEmpty) 0L else edges.map(_(2)).max

    def check(X: Long): Boolean = {
        val valid = Array.tabulate(n)(i => i == 0 || i == n - 1 || online(i))
        val adj = Array.fill(n)(mutable.ArrayBuffer.empty[(Int, Long)])
        for (e <- edges) {
            val u = e(0).toInt
            val v = e(1).toInt
            val cost_val = e(2)
            if (cost_val >= X && valid(u) && valid(v)) {
                adj(u) += ((v, cost_val))
            }
        }

        val dist = Array.fill(n)(Long.MaxValue)
        dist(0) = 0
        val pq = mutable.PriorityQueue.empty[(Long, Int)](
            new Ordering[(Long, Int)] {
                def compare(a: (Long, Int), b: (Long, Int)): Int = {
                    if (a._1 < b._1) 1
                    else if (a._1 > b._1) -1
                    else 0
                }
            }
        )
        pq.enqueue((0L, 0))

        while (pq.nonEmpty) {
            val (d, u) = pq.dequeue()
            if (d == dist(u)) {
                if (u == n - 1) {
                    return true
                }
                for ((v, c) <- adj(u)) {
                    val newCost = d + c
                    if (newCost <= k && newCost < dist(v)) {
                        dist(v) = newCost
                        pq.enqueue((newCost, v))
                    }
                }
            }
        }
        false
    }

    var low: Long = 0
    var high: Long = maxEdge
    var ans: Long = -1
    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            ans = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }
    ans
}
```

