import scala.collection.mutable

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
    val n = online.length
    val validNode = Array.tabulate(n)(i => if (i == 0 || i == n-1) true else online(i))
    if (n == 1) {
        if (0 <= k) 0 else -1
    } else {
        val maxC = edges.flatMap(_.drop(2).headOption).reduceOption(_ max _).getOrElse(0L)
        var low = 0L
        var high = maxC
        var ans = -1L

        def check(x: Long): Boolean = {
            val INF = Long.MaxValue
            val dp = Array.fill(n)(INF)
            val indegree = Array.fill(n)(0)
            val graph = Array.fill(n)(mutable.ListBuffer.empty[(Int, Long)])

            for (e <- edges) {
                val u = e(0).toInt
                val v = e(1).toInt
                val c = e(2)
                if (c >= x && validNode(u) && validNode(v) && v != 0) {
                    graph(u).append((v, c))
                    indegree(v) += 1
                }
            }

            val q = mutable.Queue[Int]()
            dp(0) = 0
            if (indegree(0) == 0) q.enqueue(0)

            while (q.nonEmpty) {
                val u = q.dequeue()
                for ((v, w) <- graph(u)) {
                    val newCost = if (dp(u) == INF) INF else dp(u) + w
                    if (newCost < dp(v)) {
                        dp(v) = newCost
                    }
                    indegree(v) -= 1
                    if (indegree(v) == 0) {
                        q.enqueue(v)
                    }
                }
            }

            dp(n-1) <= k
        }

        while (low <= high) {
            val mid = (low + high) / 2
            if (check(mid)) {
                ans = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }

        ans
    }
}
```

